CREATE TABLE public.audit_logs (action text NOT NULL, id uuid NOT NULL DEFAULT uuid_generate_v4(), user_id uuid, details jsonb, created_at timestamp with time zone DEFAULT now();
CREATE TABLE public.badges (id uuid NOT NULL DEFAULT uuid_generate_v4(), awarded_at timestamp with time zone DEFAULT now(), badge_type text NOT NULL, expires_at timestamp with time zone NOT NULL, user_id uuid NOT NULL);
CREATE TABLE public.likes (id uuid NOT NULL DEFAULT uuid_generate_v4(), user_id uuid NOT NULL, created_at timestamp with time zone DEFAULT now(), post_id uuid NOT NULL);
CREATE TABLE public.listing_images (storage_path text NOT NULL, id uuid NOT NULL DEFAULT uuid_generate_v4(), post_id uuid, created_at timestamp with time zone DEFAULT now());
CREATE TABLE public.likes (id uuid NOT NULL DEFAULT uuid_generate_v4(), user_id uuid NOT NULL, created_at timestamp with time zone DEFAULT now(), post_id uuid NOT NULL);
CREATE TABLE public.listing_images (storage_path text NOT NULL, id uuid NOT NULL DEFAULT uuid_generate_v4(), post_id uuid, created_at timestamp with time zone DEFAULT now());
CREATE TABLE public.payments (currency text NOT NULL DEFAULT 'USD'::text, user_id uuid NOT NULL, amount_cents bigint NOT NULL, status USER-DEFINED DEFAULT 'pending'::payment_status, purchased_at timestamp with time zone DEFAULT now(), expires_at timestamp with time zone, id uuid NOT NULL DEFAULT uuid_generate_v4(), provider_txn_id text);
CREATE TABLE public.posts (media jsonb, allow_quotes boolean DEFAULT true, description text, title text, deleted_at timestamp with time zone, created_at timestamp with time zone DEFAULT now(), estimated_price_cents bigint, visibility_score numeric DEFAULT 0, id uuid NOT NULL DEFAULT uuid_generate_v4(), user_id uuid NOT NULL, price_cents bigint);
CREATE TABLE public.presence_snapshots (id bigint NOT NULL DEFAULT nextval('presence_snapshots_id_seq'::regclass), snapshot_at timestamp with time zone NOT NULL DEFAULT now(), online_count integer NOT NULL);
CREATE TABLE public.quote_requests (message text, id uuid NOT NULL DEFAULT uuid_generate_v4(), post_id uuid NOT NULL, requester_user_id uuid NOT NULL, offered_price_cents bigint, status USER-DEFINED DEFAULT 'requested'::quote_status, created_at timestamp with time zone DEFAULT now(), updated_at timestamp with time zone DEFAULT now());
CREATE TABLE public.reshares (created_at timestamp with time zone DEFAULT now(), id uuid NOT NULL DEFAULT uuid_generate_v4(), post_id uuid NOT NULL, user_id uuid NOT NULL);
CREATE TABLE public.users (is_verified boolean DEFAULT false, display_name text, bio text, id uuid NOT NULL DEFAULT auth.uid(), avatar_url text, updated_at timestamp with time zone DEFAULT now(), created_at timestamp with time zone DEFAULT now(), blue_tick_expires_at timestamp with time zone);
CREATE TABLE public.verifications (status USER-DEFINED DEFAULT 'pending'::verification_status, reviewer_id uuid, method USER-DEFINED NOT NULL, user_id uuid NOT NULL, id uuid NOT NULL DEFAULT uuid_generate_v4(), data jsonb, created_at timestamp with time zone DEFAULT now(), reviewed_at timestamp with time zone);
